const data = $input.all()[0].json.data;
const hasIssue = data.qcPassRate < 0.7 || data.commonFailures.some(f => f.rate > 0.3);
const failureList = data.commonFailures.map(f => `- ${f.check}: ${f.failCount}건 (${Math.round(f.rate * 100)}%)`).join('\n');

return [{
  json: {
    hasIssue,
    total: data.totalGenerations,
    passRate: Math.round(data.qcPassRate * 100),
    avgStructural: data.avgStructuralScore,
    avgMobile: data.avgMobileScore,
    avgQc: data.avgRenderingQcScore,
    loopRate: Math.round(data.qualityLoopUsageRate * 100),
    failureList: failureList || '없음',
    period: `${data.period.from} ~ ${data.period.to}`
  }
}];

