parameters.jsCode:
const stats = $('Code: 통계 분석').item.json;
const grokRaw = $input.all()[0].json.choices?.[0]?.message?.content || '{}';
let grok;
try { grok = JSON.parse(grokRaw); } catch { grok = { severity: 'medium', summary: '분석 실패', topIssues: [], recommendedAction: 'none' }; }

const issueList = grok.topIssues?.map((i, idx) => `${idx + 1}. **${i.issue}**
   → ${i.suggestedFix}`).join('
') || '없음';

const body = `## 일일 QC 리포트 (${stats.period})

` +
  `| 항목 | 값 |
|------|-----|
` +
  `| 생성 수 | ${stats.total}건 |
` +
  `| QC 통과율 | ${stats.passRate}% |
` +
  `| 구조 점수 | ${stats.avgStructural} |
` +
  `| 모바일 점수 | ${stats.avgMobile} |
` +
  `| 렌더링 QC | ${stats.avgQc} |
` +
  `| 품질루프 사용 | ${stats.loopRate}% |

` +
  `## SuperGrok 분석 (심각도: ${grok.severity})

${grok.summary}

` +
  `### 주요 이슈
${issueList}

` +
  `### 실패 현황
${stats.failureList}

` +
  `> 권장 조치: ${grok.recommendedAction}`;

return [{ json: { title: `[QC Daily] ${grok.severity}: ${grok.summary}`, body, severity: grok.severity, action: grok.recommendedAction, grok } }];
